To find images with the same content but different names in Kotlin, you can use a hashing algorithm like MD5 to generate a hash for each image and then compare these hashes. Here's a sample implementation using the `java.security.MessageDigest` class:

```kotlin
import java.io.File
import java.security.MessageDigest
import java.security.NoSuchAlgorithmException

fun getImageHashes(directory: String): Map<String, List<File>> {
    val imageHashes = mutableMapOf<String, MutableList<File>>()

    File(directory).walk().forEach { file ->
        if (file.isFile && (file.extension == "jpg" || file.extension == "png")) {
            try {
                val hash = calculateMD5(file)
                imageHashes[hash]?.add(file) ?: imageHashes[hash]?.toMutableList()?.apply { add(file) }
            } catch (e: NoSuchAlgorithmException) {
                e.printStackTrace()
            }
        }
    }

    return imageHashes.filter { it.value.size > 1 }
}

fun calculateMD5(file: File): String {
    val digest = MessageDigest.getInstance("MD5")
    file.inputStream().use { inputStream ->
        val buffer = ByteArray(1024)
        var bytesRead: Int
        while (inputStream.read(buffer).also { bytesRead = it } != -1) {
            digest.update(buffer, 0, bytesRead)
        }
    }
    return digest.digest().fold("", { str, it -> str + "%02x".format(it) })
}
```

You can call `getImageHashes` with the directory containing your images, and it will return a map of hashes to lists of files with the same content.

