function generateRandomString($minLength, $maxLength, $excludeChars = []) {
    // Define the characters we want to include in the random string
    $chars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';

